"use strict";(globalThis.webpackChunkmy_website=globalThis.webpackChunkmy_website||[]).push([[7929],{1416(e,t,s){s.r(t),s.d(t,{assets:()=>h,contentTitle:()=>a,default:()=>u,frontMatter:()=>r,metadata:()=>o,toc:()=>l});const o=JSON.parse('{"id":"stoicism/epictetus/discourses/book-1/discourses-book-1-chapter-17","title":"Discourses \u2014 Book 1, Chapter 17","description":"Book 1 \u2014 Chapter 17","source":"@site/docs/stoicism/epictetus/discourses/book-1/discourses-book-1-chapter-17.md","sourceDirName":"stoicism/epictetus/discourses/book-1","slug":"/stoicism/epictetus/discourses/book-1/discourses-book-1-chapter-17","permalink":"/justinus/docs/stoicism/epictetus/discourses/book-1/discourses-book-1-chapter-17","draft":false,"unlisted":false,"tags":[],"version":"current","sidebarPosition":18,"frontMatter":{"sidebar_position":18,"title":"Discourses \u2014 Book 1, Chapter 17","sidebar_label":"Book 1, Ch. 17"},"sidebar":"philosophersSidebar","previous":{"title":"Book 1, Ch. 16","permalink":"/justinus/docs/stoicism/epictetus/discourses/book-1/discourses-book-1-chapter-16"},"next":{"title":"Book 1, Ch. 18","permalink":"/justinus/docs/stoicism/epictetus/discourses/book-1/discourses-book-1-chapter-18"}}');var i=s(4848),n=s(8453);const r={sidebar_position:18,title:"Discourses \u2014 Book 1, Chapter 17",sidebar_label:"Book 1, Ch. 17"},a="Discourses",h={},l=[{value:"Book 1 \u2014 Chapter 17",id:"book-1--chapter-17",level:2},{value:"That The Processes Of Logic Are Necessary",id:"that-the-processes-of-logic-are-necessary",level:3},{value:"Sonnet 4.6 Summary",id:"sonnet-46-summary",level:2},{value:"Text",id:"text",level:2}];function d(e){const t={em:"em",h1:"h1",h2:"h2",h3:"h3",header:"header",p:"p",...(0,n.R)(),...e.components},{Details:s}=t;return s||function(e,t){throw new Error("Expected "+(t?"component":"object")+" `"+e+"` to be defined: you likely forgot to import, pass, or provide it.")}("Details",!0),(0,i.jsxs)(i.Fragment,{children:[(0,i.jsxs)("div",{style:{textAlign:"center"},children:[(0,i.jsx)(t.header,{children:(0,i.jsx)(t.h1,{id:"discourses",children:"Discourses"})}),(0,i.jsx)(t.h2,{id:"book-1--chapter-17",children:"Book 1 \u2014 Chapter 17"}),(0,i.jsx)(t.h3,{id:"that-the-processes-of-logic-are-necessary",children:"That The Processes Of Logic Are Necessary"})]}),"\n",(0,i.jsx)(t.p,{children:(0,i.jsx)(t.em,{children:"Translated by P.E. Matheson (Oxford: Clarendon Press, 1916)"})}),"\n",(0,i.jsxs)(s,{open:!0,children:[(0,i.jsx)("summary",{children:"Sonnet 4.6 Summary"}),(0,i.jsx)(t.h2,{id:"sonnet-46-summary",children:"Sonnet 4.6 Summary"}),(0,i.jsx)(t.p,{children:"A defense of logic's indispensability, built on a simple point: reason is the instrument by which everything else is judged. Before you can measure corn, you need to know what a bushel is. Before you can evaluate any claim about the good, you need a reliable instrument of judgment. Logic is that instrument \u2014 and since it's made of reason, reason can and must examine itself."}),(0,i.jsx)(t.p,{children:"The chapter closes with a striking image: the philosopher as priest reading the entrails of a sacrifice. The message found there is always the same \u2014 your will is free and unhindered by nature. No threat of death compels you; only your own judgment that compliance is preferable to dying does that. The priest doesn't deserve admiration; the truth he interprets does."})]}),"\n",(0,i.jsxs)(s,{open:!0,children:[(0,i.jsx)("summary",{children:"Text"}),(0,i.jsx)(t.h2,{id:"text",children:"Text"}),(0,i.jsx)(t.p,{children:"SINCE it is reason which makes all other things articulate and complete, and reason itself must be analysed and made articulate, what is it that shall effect this? Plainly, reason itself or something else. That something else either is reason or it will be something superior to reason, which is impossible. If it is reason, who again will analyse that reason? For if it"}),(0,i.jsx)(t.p,{children:"analyses itself, so can the reason with which we started. If we are going to call in something else, the process will be endless and unceasing."}),(0,i.jsx)(t.p,{children:"'Yes,' says one, 'but the more pressing need is not logic but the discipline of men's thoughts and feelings', and the like."}),(0,i.jsx)(t.p,{children:"If you want to hear about moral improvement, well and good. But if you say to me, 'I do not know whether you argue truly or falsely', and if I use an ambiguous word and you say to me 'distinguish', I shall grow impatient and say to you, 'this is the more pressing need.' It is for this reason, I suppose, that men put the processes of logic in the forefront, just as we put the testing of the measure before the measuring of the corn. And if we do not determine first what is the bushel and what is the scale, how shall we be able to measure or weigh anything? So in the sphere of thought if we have not fully grasped and trained to perfection the instrument by which we judge other things and understand other things, shall we ever be able to arrive at accurate knowledge? Of course, it is impossible."}),(0,i.jsx)(t.p,{children:"'Yes,' they say, 'but the bushel is a mere thing of wood and bears no fruit.'"}),(0,i.jsx)(t.p,{children:"True, but it can measure corn."}),(0,i.jsx)(t.p,{children:"'The processes of logic, too, are unfruitful.'"}),(0,i.jsx)(t.p,{children:"This we will consider presently: but even if one should concede this, it is enough that logic has the power to analyse and distinguish other things and in fact, as one might say, has the power to weigh and measure. Who asserts this? Is it only Chrysippus and Zeno and Cleanthes? Does not Antisthenes agree? Why, who is it that has written, 'The beginning of education is the analysis of terms'? Does not Socrates too say the same? Does not Xenophon write of him that he began with the analysis of terms, to discover what each means?"}),(0,i.jsx)(t.p,{children:"Is this then what you call great and admirable--to understand or interpret Chrysippus? Nay, no one says that. What is admirable then? To understand the will of Nature. Very well: do you understand it of yourself? If so, what more do you need? For if it is true that all error is involuntary and you have learnt the truth, you must needs do rightly hereafter."}),(0,i.jsx)(t.p,{children:"'But,' you may say, 'I do not understand the will of Nature.'"}),(0,i.jsx)(t.p,{children:"Who then expounds it? They say 'Chrysippus.' I come and inquire what this interpreter of Nature says. I begin not to understand what he means and I seek some one to interpret. The interpreter says, 'Let us examine the sense of this phrase, as if it were Latin.'"}),(0,i.jsx)(t.p,{children:"Why, pray, should the interpreter put on airs? Even Chrysippus has no right to do so, if he is only expounding the will of Nature, and does not follow it himself: how much less his interpreter. For we have no need of Chrysippus for his own sake, but only to enable us to follow"}),(0,i.jsx)(t.p,{children:"[paragraph continues] Nature: just as we have no need, for himself, of the priest who offers sacrifice, but because we think that through him we shall understand the signs which the gods give of the future, nor do we need the sacrifice for itself, but because through it the sign is given, nor do we marvel at the crow or the raven but at God who gives His signs by them."}),(0,i.jsx)(t.p,{children:"So I come to this interpreter and priest and say, 'Examine the victim's flesh to see what sign is given me.' He takes and opens the flesh and interprets, 'Man, you have a will unhindered and unconstrained by nature. This is written here in the flesh of the sacrifice. I will show you the truth of it first in the sphere of assent. Can any one prevent you from agreeing to what is true? No one. Can any one compel you to accept the false? No one. Do you see that in this sphere your faculty is free from let and hindrance and constraint and compulsion? Is it any different in the sphere of will and impulse? What, I ask, can overcome impulse except another impulse? And what can overcome the will to get or will to avoid except another will to get or to avoid?'"}),(0,i.jsx)(t.p,{children:"'If he threatens me with death,' one says, 'he compels me.'"}),(0,i.jsx)(t.p,{children:"No, it is not what he threatens you with which compels you, but your decision that it is better to do what you are bidden than to die. Once more then it is your own judgement which compels you--that is, will puts pressure on will. For if God had so created that portion of His own being which He has taken from Himself and given to us, that it could suffer hindrance or compulsion from another, He would cease to be God and to care for us as He must needs do. 'This', says the priest, 'is what I find in the sacrifice: this is God's sign to you: if you will, you are free: if you will, you will blame no one, you will accuse no one: everything shall be in accordance with your own mind and the mind of God.'"}),(0,i.jsx)(t.p,{children:"This is the prophecy which draws me to consult this seer and philosopher, and his interpretation makes me admire not him but the truths which he interprets."})]})]})}function u(e={}){const{wrapper:t}={...(0,n.R)(),...e.components};return t?(0,i.jsx)(t,{...e,children:(0,i.jsx)(d,{...e})}):d(e)}},8453(e,t,s){s.d(t,{R:()=>r,x:()=>a});var o=s(6540);const i={},n=o.createContext(i);function r(e){const t=o.useContext(n);return o.useMemo(function(){return"function"==typeof e?e(t):{...t,...e}},[t,e])}function a(e){let t;return t=e.disableParentContext?"function"==typeof e.components?e.components(i):e.components||i:r(e.components),o.createElement(n.Provider,{value:t},e.children)}}}]);